419→    /// Integration test: full auto-mock pipeline for a function with mixed dependencies.
420→    /// Validates that dependencies are classified, mocks are generated with correct
421→    /// return values, pure utilities are skipped, and user overrides are applied.
422→    #[test]
423→    fn auto_mock_pipeline_mixed_dependencies() {
424→        // Simulate a function that depends on fs.readFileSync, axios.get,
425→        // pg.query, lodash.map, and a custom library.
426→        let deps = vec![
427→            make_dep("readFileSync", "fs", TypeInfo::Str),
428→            make_dep("get", "axios", TypeInfo::Unknown),
429→            make_dep("query", "pg", TypeInfo::Unknown),
430→            make_dep("map", "lodash", TypeInfo::Unknown),
431→            make_dep("compute", "my-analytics-lib", TypeInfo::Int),
432→        ];
433→
434→        // User override: custom return value for the database query mock
435→        let mut overrides = HashMap::new();
436→        overrides.insert(
437→            "query".to_string(),
438→            MockOverride {
439→                return_values: Some(vec![json!({"rows": [{"id": 1, "name": "alice"}]})]),
440→                behavior: None,
441→            },
442→        );
443→
444→        let mocks = generate_auto_mocks(&deps, None, &overrides, &[]);
445→
446→        // 4 mocks generated: fs, network, db (overridden), and external other.
447→        // lodash (pure utility) is skipped.
448→        assert_eq!(mocks.len(), 4, "expected 4 mocks (lodash skipped)");
449→
450→        let by_symbol: HashMap<&str, &MockConfig> =
451→            mocks.iter().map(|m| (m.symbol.as_str(), m)).collect();
452→
453→        // fs.readFileSync → filesystem category, returns ""
454→        let fs_mock = by_symbol["readFileSync"];
455→        assert_eq!(fs_mock.return_values, vec![json!("")]);
456→        assert!(fs_mock.should_track_calls);
457→        assert_eq!(fs_mock.default_behavior, MockBehavior::RepeatLast);
458→
459→        // axios.get → network category, returns {status: 200, data: {}}
460→        let net_mock = by_symbol["get"];
461→        assert_eq!(net_mock.return_values, vec![json!({"status": 200, "data": {}})]);
462→        assert!(net_mock.should_track_calls);
463→
464→        // pg.query → database category, but overridden with custom rows
465→        let db_mock = by_symbol["query"];
466→        assert_eq!(
467→            db_mock.return_values,
468→            vec![json!({"rows": [{"id": 1, "name": "alice"}]})]
469→        );
470→        assert!(db_mock.should_track_calls);
471→
472→        // my-analytics-lib.compute → external other, type-aware default for Int
473→        let ext_mock = by_symbol["compute"];
474→        assert_eq!(ext_mock.return_values, vec![json!(0)]);
475→        assert!(ext_mock.should_track_calls);
476→
477→        // Verify lodash.map is NOT in the mock list
478→        assert!(!by_symbol.contains_key("map"));
479→    }
