481→    /// Integration test: auto-mocks are compatible with the Instrument command format.
482→    /// Verifies that generated MockConfig values serialize correctly for the protocol.
483→    #[test]
484→    fn auto_mock_configs_serialize_for_protocol() {
485→        let deps = vec![
486→            make_dep("existsSync", "fs", TypeInfo::Bool),
487→            make_dep("query", "pg", TypeInfo::Unknown),
488→        ];
489→
490→        let mocks = generate_auto_mocks(&deps, None, &HashMap::new(), &[]);
491→        assert_eq!(mocks.len(), 2);
492→
493→        // Verify each mock serializes to valid JSON (required for protocol)
494→        for mock in &mocks {
495→            let json = serde_json::to_value(mock).expect("mock should serialize");
496→            assert!(json.get("symbol").is_some());
497→            assert!(json.get("return_values").is_some());
498→            assert!(json.get("should_track_calls").is_some());
499→            assert!(json.get("default_behavior").is_some());
