503→    /// Integration test: auto-mocks respect scope configuration.
504→    /// Dependencies marked as passthrough in scope config are excluded from mocking.
505→    #[test]
506→    fn auto_mock_pipeline_with_scope_rules() {
507→        let deps = vec![
508→            make_dep("readFile", "fs", TypeInfo::Str),
509→            make_dep("get", "axios", TypeInfo::Unknown),
510→            make_dep("query", "pg", TypeInfo::Unknown),
511→        ];
512→
513→        // Scope config: mark axios.get as passthrough (e.g., user wants real HTTP)
514→        let scope_config = crate::scope::ScopeConfig {
515→            include: vec![],
516→            exclude: vec![],
517→            mock: vec![],
518→            passthrough: vec!["get".to_string()],
519→        };
520→        let matcher = ScopeMatcher::new(&scope_config).unwrap();
521→
522→        let mocks = generate_auto_mocks(&deps, Some(&matcher), &HashMap::new(), &[]);
523→
524→        // Only 2 mocks: fs.readFile and pg.query. axios.get is passthrough.
525→        assert_eq!(mocks.len(), 2);
526→        let symbols: Vec<&str> = mocks.iter().map(|m| m.symbol.as_str()).collect();
527→        assert!(symbols.contains(&"readFile"));
528→        assert!(symbols.contains(&"query"));
529→        assert!(!symbols.contains(&"get"));
530→    }
