561→    fn generate_auto_mocks_for_multiple_deps() {
562→        let deps = vec![
563→            make_dep("readFile", "fs", TypeInfo::Str),
564→            make_dep("get", "axios", TypeInfo::Unknown),
565→            make_dep("map", "lodash", TypeInfo::Unknown),
566→            make_dep("compute", "my-lib", TypeInfo::Int),
567→        ];
568→
569→        let result = generate_auto_mocks(&deps, None, &HashMap::new(), &[]);
570→        // lodash (pure utility) is skipped
571→        assert_eq!(result.len(), 3);
572→        let symbols: Vec<&str> = result.iter().map(|m| m.symbol.as_str()).collect();
573→        assert!(symbols.contains(&"readFile"));
574→        assert!(symbols.contains(&"get"));
575→        assert!(symbols.contains(&"compute"));
576→    }
577→}
