 61→impl ScopeConfig {
 62→    /// Read and parse a scope configuration from a YAML file.
 63→    pub fn from_file(path: &Path) -> Result<Self, ScopeError> {
 64→        let contents = std::fs::read_to_string(path)?;
 65→        let file: ScopeFile = serde_yaml::from_str(&contents)?;
