 70→/// What to do with a dependency.
 71→#[derive(Debug, Clone, Copy, PartialEq, Eq)]
 72→pub enum DependencyAction {
 73→    /// Replace the dependency with a mock.
 74→    Mock,
 75→    /// Leave the dependency as a real call.
 76→    Passthrough,
 77→    /// No rule matched — analyze normally.
 78→    Analyze,
 79→}
 80→
 81→/// Compiled scope matcher using `GlobSet` for efficient pattern matching.
 82→pub struct ScopeMatcher {
 83→    include: GlobSet,
 84→    exclude: GlobSet,
 85→    mock: GlobSet,
 86→    passthrough: GlobSet,
 87→}
 88→
 89→impl ScopeMatcher {
 90→    /// Compile a `ScopeConfig` into a matcher.
 91→    pub fn new(config: &ScopeConfig) -> Result<Self, ScopeError> {
 92→        Ok(Self {
 93→            include: build_glob_set(&config.include)?,
 94→            exclude: build_glob_set(&config.exclude)?,
 95→            mock: build_glob_set(&config.mock)?,
 96→            passthrough: build_glob_set(&config.passthrough)?,
 97→        })
 98→    }
 99→
100→    /// Returns `true` if the path matches include patterns and does not match exclude patterns.
101→    ///
102→    /// If no include patterns are defined, all paths are considered included.
103→    pub fn is_included(&self, path: &str) -> bool {
104→        let included = self.include.is_empty() || self.include.is_match(path);
105→        let excluded = self.exclude.is_match(path);
106→        included && !excluded
107→    }
108→
109→    /// Classify a dependency symbol/path as Mock, Passthrough, or Analyze.
110→    ///
111→    /// Passthrough takes precedence over Mock (more specific override).
112→    pub fn classify_dependency(&self, symbol: &str) -> DependencyAction {
113→        if self.passthrough.is_match(symbol) {
114→            return DependencyAction::Passthrough;
115→        }
116→        if self.mock.is_match(symbol) {
117→            return DependencyAction::Mock;
118→        }
119→        DependencyAction::Analyze
120→    }
121→}
122→
123→fn build_glob_set(patterns: &[String]) -> Result<GlobSet, ScopeError> {
124→    let mut builder = GlobSetBuilder::new();
125→    for pattern in patterns {
126→        builder.add(Glob::new(pattern)?);
127→    }
128→    Ok(builder.build()?)
129→}
